# -----------------------------------------------------------------------
# When steps — bootstrap / update invocation
# -----------------------------------------------------------------------


@when(
    parsers.parse(
        'I invoke the "shop-templates" bootstrap entry point with shop type '
        '"{shop_type}", shop name "{shop_name}", and target directory "{alias}"'
    )
)
def when_invoke_bootstrap(
    shop_type: str,
    shop_name: str,
    alias: str,
    context: dict,
    tmp_path: Path,
) -> None:
    # lead-llc1 scenarios 568e33d4 / d8b53704 carry the literal "<slug>"
    # placeholder as the shop name, standing for "any slug". Fan the single
    # invocation out into a default (shopsystem) and a non-default (dummyco)
    # bootstrap so the broker-render / .env.example Then steps can assert
    # across both. (No real scenario passes a literal "<slug>" to bootstrap;
    # this branch is inert for every other When.)
    if shop_name == "<slug>":
        _llc1_bootstrap_both_slugs(shop_type, alias, context, tmp_path)
        return
    # tmpl-4k7 / scenario 9e15d8cfd55b9541 carries the literal "<shop_name>"
    # placeholder as the shop name, standing for "the product shop name". Bind
    # it to the canonical lead-shop example name every other lead scenario uses
    # so the .beads/config.yaml Then steps can derive the expected product
    # beads remote / issue prefix from the bound name. (No real scenario passes
    # a literal "<shop_name>" to bootstrap; this branch is inert otherwise.)
    if shop_name == "<shop_name>":
        shop_name = "shopsystem-product"
    real = _real_target_for_alias(alias, context)
    result = _run_shop_templates_with_bd_shim(
        [
            "bootstrap",
            "--shop-type",
            shop_type,
            "--shop-name",
            shop_name,
            "--target",
            str(real),
        ],
        context,
        tmp_path,
    )
    context["cli_returncode"] = result.returncode
    context["cli_stdout"] = result.stdout
    context["cli_stderr"] = result.stderr
    context["last_invocation_target"] = real
    context["last_invocation_shop_type"] = shop_type
    context["last_invocation_shop_name"] = shop_name


