# Release-workflow repository_dispatch to bc-launcher
# (lead-jx4u, scenario 26ca8a14e01db50c) — RETIRED per ADR-022 (lead-zgrk).
#
# ADR-022 centralizes bc-base rebuilds in shopsystem-bc-launcher's
# scheduled version-bump-then-rebuild poll and supersedes the per-repo
# repository_dispatch fan-in trigger of ADR-021 D2. Under ADR-022
# shopsystem-templates emits NOTHING on release, so the scenario that
# pinned "templates emits a repository_dispatch to bc-launcher" is a pure
# retirement with no successor. The feature file and the step definitions
# that backed it have been removed; the forward-looking guard that the
# release workflow carries NO repository_dispatch / NO
# BC_LAUNCHER_DISPATCH_TOKEN now lives in
# tests/test_release_version_tag_guard.py.
#
# (The shared helper _bc_repo_root() below is retained — it is also used
# by unrelated step definitions later in this module.)
# =======================================================================

def _bc_repo_root() -> Path:
    # tests/ sits directly under the BC repo root.
    return Path(__file__).resolve().parent.parent


