# -----------------------------------------------------------------------
# Then steps — identity-precedes-procedure structural integrity
# (scenario_hash:662c5822dbc6a896 — lead-y8rz)
#
# The four durable PM discipline names that headings must not promote
# above depth ### (3). Any heading whose text contains one of these
# strings must appear at #### (4) or deeper; appearing at ## (2) or
# # (1) would violate identity-precedes-procedure.
# -----------------------------------------------------------------------

_PM_DISCIPLINE_NAMES = (
    "problem discovery & selection",
    "outcome ownership",
    "strategy before backlog",
    "specification as the contract",
)


@then(
    "every heading whose text mentions a PM discipline appears at heading depth "
    "three (###) or deeper, never at depth one (#)"
)
def then_pm_discipline_headings_at_depth_three_or_deeper(context: dict) -> None:
    """Each heading containing a PM discipline name must be at ### or deeper.

    The four durable disciplines — problem discovery & selection, outcome
    ownership, strategy before backlog, specification as the contract — must
    not appear as depth-1 (#) headings. Doing so would place procedural PM
    framework content at the identity level of the document, violating the
    identity-precedes-procedure ordering.
    """
    content = context["template_content"]
    offenders: list[tuple[int, str, str]] = []
    for lineno, line in enumerate(content.splitlines(), start=1):
        stripped = line.lstrip()
        if not stripped.startswith("#"):
            continue
        # Count the leading # characters to determine depth.
        depth = 0
        for ch in stripped:
            if ch == "#":
                depth += 1
            else:
                break
        if depth >= 3:
            continue  # depth 3 or deeper is fine
        heading_text_lower = stripped.lstrip("#").strip().lower()
        for discipline in _PM_DISCIPLINE_NAMES:
            if discipline.lower() in heading_text_lower:
                offenders.append((lineno, line.rstrip(), discipline))
    assert not offenders, (
        f"template {context.get('shown_template_name')!r} has PM discipline "
        f"headings at depth < 3 (violates identity-precedes-procedure, "
        f"scenario_hash:662c5822dbc6a896):\n"
        + "\n".join(
            f"  line {n}: {l!r} (mentions discipline {d!r})"
            for n, l, d in offenders
        )
    )


@then(
    "the first occurrence of the substring \"shop-msg\" in the content appears "
    "after every PM discipline name has appeared at least once"
)
def then_shop_msg_after_all_pm_discipline_names(context: dict) -> None:
    """First 'shop-msg' must follow all four PM discipline names.

    All four durable PM discipline names must appear in the content before
    the first occurrence of 'shop-msg'. This enforces that the PM identity
    content (who the PM is and what disciplines they hold) precedes the
    procedural CLI mechanics.
    """
    content = context["template_content"]
    shop_msg_idx = content.find("shop-msg")
    assert shop_msg_idx >= 0, (
        f"premise of Then violated: template "
        f"{context.get('shown_template_name')!r} has no 'shop-msg' substring"
    )
    missing: list[str] = []
    too_late: list[tuple[str, int, int]] = []
    for discipline in _PM_DISCIPLINE_NAMES:
        idx = content.lower().find(discipline.lower())
        if idx < 0:
            missing.append(discipline)
            continue
        if idx >= shop_msg_idx:
            too_late.append((discipline, idx, shop_msg_idx))
    assert not missing, (
        f"premise of Then violated: template "
        f"{context.get('shown_template_name')!r} is missing PM discipline "
        f"name(s): {missing!r} (scenario_hash:662c5822dbc6a896)"
    )
    assert not too_late, (
        f"first 'shop-msg' at byte {shop_msg_idx} in template "
        f"{context.get('shown_template_name')!r} precedes PM discipline "
        f"name(s) (each must appear at least once before 'shop-msg'):\n"
        + "\n".join(
            f"  - {d!r} first appears at byte {di} (>= {smi})"
            for d, di, smi in too_late
        )
        + f"\n(scenario_hash:662c5822dbc6a896)"
    )


# -----------------------------------------------------------------------
# Step definitions — session-start work-tracker health step (lead-80t0).
#
# The 5 scenarios pin a NEW session-start step in the BC session-start
# contract: a work-tracker health step that runs BEFORE the role loop and
# gates it. The step heals an unprovisioned-but-recoverable bd tracker
# (adopt committed issue_prefix + import committed issues), validates local
# writability (bd create / bd ready) AND a test dolt push to the configured
# remote, and otherwise surfaces an explicit failure at session-start —
# never deferring to work_done emission time.
#
# The assertable artifact is the rendered session-start surface: the
# canonical bc primer body (`read_claude_md_primer("bc")`) together with the
# bc-router skill body (`iter_skill_files()["bc-router/SKILL.md"]`). The
# When step loads that combined rendered surface through the package's
# public template-access surface; each Then step asserts the health-step
# contract is present in that rendered surface so the scenarios are pinned
# to observable rendering, not prose.
# -----------------------------------------------------------------------


def _load_bc_session_start_surface() -> dict:
    """Load the rendered BC session-start surface through the public
    template-access surface: the bc primer body + the bc-router skill body.

    Returns a dict carrying each body and a lowercased concatenation for
    substring assertions. No filesystem-path reads — everything comes from
    importlib.resources package data via the public accessors.
    """
    from shop_templates.cli import read_claude_md_primer, iter_skill_files

    primer = read_claude_md_primer("bc")
    skills = dict(iter_skill_files())
    router = skills["bc-router/SKILL.md"].decode()
    combined = primer + "\n" + router
    return {
        "primer": primer,
        "router": router,
        "combined": combined,
        "combined_lower": combined.lower(),
    }


def _assert_health_step_present(surface: dict) -> None:
    """The rendered surface must carry a session-start work-tracker health
    step that runs BEFORE the role loop. Pinned by the literal contract
    vocabulary the health step renders with."""
    body = surface["combined_lower"]
    assert "work-tracker health" in body, (
        "rendered BC session-start surface does not name a 'work-tracker "
        "health' step"
    )
    # The step must be a SESSION-START step that gates the role loop — the
    # rendered surface must connect the health step to the role loop start.
    assert "role loop" in body, (
        "rendered surface does not connect the work-tracker health step to "
        "the role loop"
    )


@when("the BC agent session starts and runs the work-tracker health step")
def when_session_runs_health_step(context: dict) -> None:
    context["health_surface"] = _load_bc_session_start_surface()


@when(
    "the BC agent session starts and the work-tracker health step heals "
    "the tracker"
)
def when_session_health_step_heals(context: dict) -> None:
    context["health_surface"] = _load_bc_session_start_surface()


