@then(
    parsers.re(
        r'every value in the rendered "\.env\.example" is a placeholder, '
        r'carrying no real secret material'
    )
)
def then_env_example_values_are_placeholders(context: dict) -> None:
    import re as _re

    for slug in _LLC1_SLUGS:
        text = _llc1_env_example_text(context, slug)
        for ln in text.splitlines():
            stripped = ln.strip()
            if not stripped or stripped.startswith("#") or "=" not in stripped:
                continue
            key, _, value = stripped.partition("=")
            key = key.strip()
            value = value.strip().strip('"').strip("'")
            if value == "":
                # An empty value is a placeholder (operator fills it in).
                continue
            # A placeholder value: angle-bracketed/CHANGEME/changeme-style or
            # the key name echoed — never opaque high-entropy secret material.
            low = value.lower()
            looks_placeholder = (
                value.startswith("<")
                or value.endswith(">")
                or "changeme" in low
                or "placeholder" in low
                or "example" in low
                or "your-" in low
                or "your_" in low
                or "..." in value
                or "paste" in low
                or "fill" in low
                or "replace" in low
                or value == key
                or value.startswith("${")
                or all(c in "x-_" for c in low)
            )
            assert looks_placeholder, (
                f"{slug} .env.example value for {key!r} looks like real "
                f"secret material, not a placeholder: {value!r}"
            )
            # Defensive: no long opaque base64/hex token slipped in.
            assert not _re.fullmatch(r"[A-Za-z0-9+/=]{24,}", value), (
                f"{slug} .env.example {key!r} carries opaque secret-looking "
                f"material: {value!r}"
            )


@then(
    parsers.re(
        r'the "\.env\.example" file is additive: it does not appear in and '
        r'does not alter the existing six shop-owned ops-tool files '
        r'\("compose\.yaml", "bin/shop-shell", "Dockerfile\.<slug>-shell", '
        r'"bin/shop-scenario-completion", "bin/agent-vault-provision", '
        r'"bin/agent-vault-check"\), so the existing six-file ops-tool '
        r'enumeration stays non-regressing'
    )
)
def then_env_example_is_additive(context: dict) -> None:
    from shop_templates.cli import _LEAD_OPS_FILES

    # .env.example is NOT one of the six enumerated ops-tool files.
    ops_rel = {rel for _tn, rel, _exe in _LEAD_OPS_FILES}
    ops_tmpl = {tn for tn, _rel, _exe in _LEAD_OPS_FILES}
    assert ".env.example" not in ops_rel, (
        ".env.example must not be enumerated in the six-file ops-tool set"
    )
    assert ".env.example" not in ops_tmpl
    assert len(_LEAD_OPS_FILES) == 6, (
        f"the ops-tool set must stay exactly six files; got {len(_LEAD_OPS_FILES)}"
    )
    for slug in _LLC1_SLUGS:
        target = _llc1_renders(context)[slug]
        # The six ops-tool files all still render at their pinned paths.
        for _tn, rel, _exe in _LEAD_OPS_FILES:
            on_disk = rel
            if rel == "Dockerfile.shopsystem-shell":
                on_disk = f"Dockerfile.{slug}-shell"
            assert (target / on_disk).is_file(), (
                f"{slug} bootstrap is missing ops-tool file {on_disk}"
            )
        # And .env.example is a distinct top-level file, not one of those six.
        env_path = target / ".env.example"
        assert env_path.is_file()
        six_paths = set()
        for _tn, rel, _exe in _LEAD_OPS_FILES:
            on_disk = rel
            if rel == "Dockerfile.shopsystem-shell":
                on_disk = f"Dockerfile.{slug}-shell"
            six_paths.add((target / on_disk).resolve())
        assert env_path.resolve() not in six_paths, (
            ".env.example must be a distinct file outside the six-file set"
        )


# -- Scenario f02f9491b3a43753 (tmpl-4k7: .env.example documents the run
# credentials — additive pin layered on the d8b53704ce2e6584 scaffold) ---


@then(
    parsers.re(
        r'the target directory contains a file "(?P<name>\.env\.example)" '
        r'documenting the run environment variables including the agent-vault '
        r'master password and proxy token'
    )
)
def then_env_example_documents_run_credentials(name: str, context: dict) -> None:
    target = context["last_invocation_target"]
    path = target / name
    assert path.is_file(), (
        f"bootstrap did not render a top-level {name} at {target}"
    )
    text = path.read_text()

    # The scaffold must carry an assignment line for each run credential the
    # operator supplies (so `cp .env.example .env` is executable as written).
    assign_keys = {
        ln.split("=", 1)[0].strip()
        for ln in text.splitlines()
        if ln.strip() and not ln.lstrip().startswith("#") and "=" in ln
    }
    # The agent-vault master password — the broker auto-unseal credential.
    assert "AGENT_VAULT_MASTER_PASSWORD" in assign_keys, (
        f"{name} does not document the agent-vault master password "
        f"(AGENT_VAULT_MASTER_PASSWORD); assignment keys={sorted(assign_keys)}"
    )
    # The proxy token — the broker token bin/shop-shell presents and exports
    # to wire the HTTPS proxy. Reuse the existing credential vocabulary
    # (AGENT_VAULT_TOKEN); do not invent a new variable name.
    assert "AGENT_VAULT_TOKEN" in assign_keys, (
        f"{name} does not document the proxy token (AGENT_VAULT_TOKEN); "
        f"assignment keys={sorted(assign_keys)}"
    )

    # The scaffold must DOCUMENT each variable — not merely assign it. Each of
    # the master password and the proxy token carries an explanatory comment on
    # its OWN documentation line(s) (the comment block immediately preceding the
    # assignment), naming the variable's role. We attribute each leading comment
    # block to the assignment it precedes.
    lines = text.splitlines()
    doc_for: dict[str, str] = {}
    pending: list[str] = []
    for ln in lines:
        stripped = ln.strip()
        if stripped.startswith("#"):
            pending.append(stripped.lstrip("#").strip())
        elif "=" in stripped and stripped and not stripped.startswith("#"):
            key = stripped.split("=", 1)[0].strip()
            doc_for[key] = " ".join(pending).lower()
            pending = []
        elif not stripped:
            # Blank line ends a free-standing header block; do not attribute it
            # to the next assignment.
            pending = []

    mp_doc = doc_for.get("AGENT_VAULT_MASTER_PASSWORD", "")
    assert "master password" in mp_doc, (
        f"{name} assigns AGENT_VAULT_MASTER_PASSWORD but its documentation does "
        f"not name it as the master password:\n{text}"
    )
    # "proxy token": the token's OWN documentation must name its role in wiring
    # the proxy, so the operator understands AGENT_VAULT_TOKEN is the credential
    # the shop-shell presents on the HTTPS-proxy path (not merely "broker
    # auth"). This is the additive guarantee this scenario pins — the prior
    # d8b53704 scaffold documented AGENT_VAULT_TOKEN only as "broker auth".
    token_doc = doc_for.get("AGENT_VAULT_TOKEN", "")
    assert "proxy" in token_doc, (
        f"{name} documents AGENT_VAULT_TOKEN but its own documentation does not "
        f"name it as the proxy token (the token wiring the HTTPS proxy); "
        f"doc={token_doc!r}\n{text}"
    )


# -----------------------------------------------------------------------
# Step definitions — canonical LEAD skill-group (lead-5mr5)
#
# Scenarios 75f86e53/c20785332/cc520034/f75eb04e (bootstrap + access) and
# e803b4c9/4a008549/a14e5a0a (update). The lead skill-group is a distinct
# package-data subtree (templates/lead_skills/) from the BC skill tree
# (templates/skills/); lead bootstrap pours ONLY the lead group, bc
# bootstrap continues to pour the BC tree.
# -----------------------------------------------------------------------

from shop_templates.cli import (  # noqa: E402
    iter_lead_skill_files as _iter_lead_skill_files,
    canonical_skill_group as _canonical_skill_group,
)


def _lead_skill_group_members() -> dict:
    """Return {member_name: SKILL.md bytes} for the canonical lead group."""
    members = {}
    for rel, body in _iter_lead_skill_files():
        # rel is "<name>/SKILL.md"
        name = rel.split("/", 1)[0]
        if rel == f"{name}/SKILL.md":
            members[name] = body
    return members


@given(
    parsers.parse(
        'an existing git repository at a target directory "{alias}" '
        'with no ".claude/skills/" directory'
    )
)
def given_existing_git_repo_no_skills_dir(
    alias: str, context: dict, tmp_path: Path
) -> None:
    context["bootstrap_workspace"] = tmp_path
    real = _real_target_for_alias(alias, context)
    skills = real / ".claude" / "skills"
    assert not skills.exists(), (
        f"premise of Given violated: {skills!s} unexpectedly exists"
    )


@then(
    parsers.parse(
        'for every skill "{skill_ph}" in the canonical lead skill-group the '
        'target directory contains a file at ".claude/skills/{skill_ph2}/SKILL.md"'
    )
)
def then_every_lead_skill_poured(skill_ph, skill_ph2, context: dict) -> None:
    real = context["last_invocation_target"]
    members = _lead_skill_group_members()
    assert members, "the canonical lead skill-group is empty"
    for name in members:
        dest = real / ".claude" / "skills" / name / "SKILL.md"
        assert dest.is_file(), (
            f"lead-skill-group member {name!r} not poured at {dest!s}"
        )


@then(
    parsers.parse(
        'the content of each such ".claude/skills/{skill_ph}/SKILL.md" file '
        'equals the package-data file contents of that canonical lead skill '
        'template byte-for-byte'
    )
)
def then_each_lead_skill_byte_for_byte(skill_ph, context: dict) -> None:
    real = context["last_invocation_target"]
    for name, body in _lead_skill_group_members().items():
        dest = real / ".claude" / "skills" / name / "SKILL.md"
        assert dest.read_bytes() == body, (
            f"poured lead-skill {name!r} content drifts from package data"
        )


@given(
    parsers.parse(
        'the target directory contains an unmanaged skill directory '
        '".claude/skills/{unmanaged}/" with a "SKILL.md" file whose '
        'directory name is not a member of the canonical lead skill-group'
    )
)
def given_unmanaged_skill_dir(
    unmanaged: str, context: dict, tmp_path: Path
) -> None:
    # The preceding bare "an existing git repository at a target directory"
    # Given stashes bootstrap_workspace and creates the target-alias mapping
    # for the scenario's single "<target>" (/tmp/example-lead-shop). Resolve
    # that same alias so the unmanaged dir is seeded under the very target the
    # When will bootstrap. (setdefault guards against ordering surprises.)
    context.setdefault("bootstrap_workspace", tmp_path)
    real = _real_target_for_alias("/tmp/example-lead-shop", context)
    members = set(_lead_skill_group_members())
    assert unmanaged not in members, (
        f"premise of Given violated: {unmanaged!r} is a canonical "
        f"lead-skill-group member"
    )
    unmanaged_dir = real / ".claude" / "skills" / unmanaged
    unmanaged_dir.mkdir(parents=True, exist_ok=True)
    body = (
        f"# {unmanaged}\n\nExperimentally-adopted unmanaged skill body.\n"
    ).encode()
    (unmanaged_dir / "SKILL.md").write_bytes(body)
    context["unmanaged_skill_name"] = unmanaged
    context["unmanaged_skill_body"] = body


@then(
    parsers.parse(
        'any pruning the invocation performs under ".claude/skills/" removes '
        'only directories whose name is a member of the canonical lead '
        'skill-group, and never removes a directory whose name is not a '
        'canonical lead skill-group member'
    )
)
def then_pruning_scoped_to_managed_members(context: dict) -> None:
    real = context["last_invocation_target"]
    skills_root = real / ".claude" / "skills"
    present_dirs = {
        p.name for p in skills_root.iterdir() if p.is_dir()
    } if skills_root.exists() else set()
    # A non-member directory present before the invocation must NOT have been
    # pruned — its name must still be present afterwards.
    unmanaged = context["unmanaged_skill_name"]
    assert unmanaged in present_dirs, (
        f"the invocation pruned non-member skill dir {unmanaged!r}: "
        f"pruning is not scoped to canonical-managed members "
        f"(present dirs: {sorted(present_dirs)})"
    )


@then(
    parsers.parse(
        'the unmanaged skill directory ".claude/skills/{unmanaged}/" and its '
        '"SKILL.md" file are still present after the invocation with their '
        'pre-invocation contents preserved byte-for-byte'
    )
)
def then_unmanaged_skill_survives(unmanaged: str, context: dict) -> None:
    real = context["last_invocation_target"]
    skill_md = real / ".claude" / "skills" / unmanaged / "SKILL.md"
