# =======================================================================
# tmpl-am6 (corrected re-dispatch, supersedes tmpl-4k7's cosmetic A) —
# bootstrap configures the REAL bd dolt push remote and issue prefix.
# Scenario 0636fba2c1445f9f.
#
# The prior cosmetic scenario 9e15d8cfd55b9541 (which made bootstrap write
# `sync.remote` / `issue_prefix` keys into .beads/config.yaml) is RETIRED:
# bd does not read those YAML keys. The corrected contract (verified against
# bd help):
#   * the bd dolt push remote is a DB-side remote configured via
#     `bd dolt remote add <name> <url>`, listed by `bd dolt remote list`
#     (NOT the `sync.remote` jsonl-sync YAML key);
#   * the issue prefix is set via `bd init --prefix <prefix>` and read via
#     the HYPHENATED config key `bd config get issue-prefix`.
#
# "the product beads remote" and "the product-derived prefix" are derived
# from the bound --shop-name using the conventions already observable in the
# shop-system: the beads remote mirrors the committed convention
# `git+https://github.com/dstengle/<shop-name>-beads.git`, and the issue
# prefix is the product slug (the --shop-name with a single trailing
# "-product" suffix stripped — the same _ops_slug derivation the ops
# scaffolding uses). These expectations are computed here independently of
# the src so the test pins behavior rather than re-deriving against the
# implementation.
#
# The Then-steps observe the configured state through the bd-shim itself:
# they re-invoke the shim's `bd dolt remote list` / `bd config get
# issue-prefix` in the target directory (the shim persists the remote add
# and the `bd init --prefix` value as real bd would) and assert on output.
# =======================================================================


def _expected_product_beads_remote(shop_name: str, target=None) -> str:
    # ADR-043 D4/D5 (lead-clyf): the configured beads remote is single-sourced —
    # canonical "<product>-lead-beads" name, origin-derived owner (or the
    # ORIGIN_OWNER placeholder when the target has no origin), no baked dstengle.
    # Delegate to production so the expected exactly mirrors what bootstrap wires.
    from shop_templates.cli import _product_beads_remote, _origin_owner
    owner = _origin_owner(target) if target is not None else None
    return _product_beads_remote(shop_name, owner)


def _expected_product_issue_prefix(shop_name: str) -> str:
    suffix = "-product"
    if shop_name.endswith(suffix) and len(shop_name) > len(suffix):
        return shop_name[: -len(suffix)]
    return shop_name


def _run_bd_shim_query(context: dict, target: Path, args: list[str]):
    """Re-invoke the per-test bd-shim with `args` in `target` and return the
    CompletedProcess. Used by the corrected-scenario Then-steps to read the
    state bootstrap configured (`bd dolt remote list`, `bd config get
    issue-prefix`) the same way an operator would — through the bd CLI,
    against the shim that models real bd's state."""
    import subprocess as _sp

    log = context["bd_shim_log"]
    bd_path = log.parent / "bd-shim" / "bd"
    assert bd_path.exists(), (
        f"bd-shim not found at {bd_path!s}; a bootstrap invocation must run "
        f"before querying shim state"
    )
    return _sp.run(
        [str(bd_path), *args],
        cwd=str(target),
        capture_output=True,
        text=True,
    )


@then(
    parsers.parse(
        '"bd dolt remote list" in the target directory lists a dolt push '
        'remote whose URL is the product beads remote'
    )
)
def then_bd_dolt_remote_list_has_product_remote(context: dict) -> None:
    real = context["last_invocation_target"]
    expected = _expected_product_beads_remote(
        context["last_invocation_shop_name"]
    )
    result = _run_bd_shim_query(context, real, ["dolt", "remote", "list"])
    assert result.returncode == 0, (
        f"expected `bd dolt remote list` to exit 0 in {real!s}; got "
        f"{result.returncode} (stderr: {result.stderr!r})"
    )
    assert expected in result.stdout, (
        f"expected `bd dolt remote list` to list a remote whose URL is the "
        f"product beads remote {expected!r}; got stdout: {result.stdout!r}"
    )


@then(
    parsers.parse(
        '"bd config get issue-prefix" in the target directory returns the '
        'product-derived prefix'
    )
)
def then_bd_config_get_issue_prefix_returns_prefix(context: dict) -> None:
    real = context["last_invocation_target"]
    expected = _expected_product_issue_prefix(
        context["last_invocation_shop_name"]
    )
    result = _run_bd_shim_query(context, real, ["config", "get", "issue-prefix"])
    assert result.returncode == 0, (
        f"expected `bd config get issue-prefix` to exit 0 in {real!s}; got "
        f"{result.returncode} (stderr: {result.stderr!r})"
    )
    got = result.stdout.strip()
    assert got == expected, (
        f"expected `bd config get issue-prefix` to return the product-derived "
        f"prefix {expected!r}; got {got!r}"
    )


# =======================================================================
# tmpl-4k7 — bootstrap runs a `bd dolt push` smoke-test against the rendered
# beads config. Scenario 62eb2a8b9b617f4b.
#
# After rendering .beads/config.yaml (the prior behavior A, pinned by
# 9e15d8cfd55b9541), bootstrap proves the freshly-wired tracker can reach its
# configured `sync.remote` by running `bd dolt push` as a subprocess. On
# success bootstrap reports success; on a non-zero push it exits non-zero with
# a diagnostic. The failure path is driven by the bd-shim failure-injection
# toggle (context["bd_shim_fail_dolt_push"]) so no real remote is contacted.
#
# The "configured sync.remote" the smoke-test pushes against is the value
# _render_beads_config wrote — derived independently here as the product beads
# remote for the bound shop name (same convention behavior A pinned).
# =======================================================================


_SMOKE_TEST_SHOP_NAME = "shopsystem-product"
_SMOKE_TEST_TARGET_ALIAS = "/tmp/example-smoke-shop"


def _bootstrap_for_smoke_test(
    context: dict, tmp_path: Path, fail_dolt_push: bool
) -> subprocess.CompletedProcess:
    """Run a lead-shop bootstrap (with the bd shim) into a fresh target,
    optionally driving the shim's `bd dolt push` to fail. Stashes the
    invocation result/target on context the Then steps read."""
    real = _real_target_for_alias(_SMOKE_TEST_TARGET_ALIAS, context)
    context["bd_shim_fail_dolt_push"] = fail_dolt_push
    result = _run_shop_templates_with_bd_shim(
        [
            "bootstrap",
            "--shop-type",
            "lead",
            "--shop-name",
            _SMOKE_TEST_SHOP_NAME,
            "--target",
            str(real),
        ],
        context,
        tmp_path,
    )
    context["cli_returncode"] = result.returncode
    context["cli_stdout"] = result.stdout
    context["cli_stderr"] = result.stderr
    context["last_invocation_target"] = real
    context["last_invocation_shop_name"] = _SMOKE_TEST_SHOP_NAME
    return result


def _run_smoke_test_with_no_remote(
    context: dict, tmp_path: Path, target: Path
) -> subprocess.CompletedProcess:
    """Invoke the production `_bd_dolt_push_smoke_test` directly against a
    target where NO dolt remote has been configured, with the bd-shim on PATH.

    This reproduces the corrected scenario's missing-remote clause ("the same
    target directory with no dolt push remote configured"): the bd-shim models
    real bd, whose bare `bd dolt push` against an unconfigured tracker is a
    no-op that prints "No remote is configured — skipping" and EXITS 0. The
    smoke-test must NOT silently pass on that — it must exit non-zero with a
    diagnostic NAMING the missing dolt remote. We call the production function
    (not a re-implementation) so the assertion binds to bootstrap's real
    behavior. Returns the wrapper subprocess result (rc = smoke-test rc;
    stderr carries the smoke-test diagnostic)."""
    import os as _os

    shim_dir = _make_bd_shim_dir(tmp_path, context)
    expected_remote = _expected_product_beads_remote(
        _SMOKE_TEST_SHOP_NAME
    )
    wrapper = tmp_path / "_run_smoke_no_remote_wrapper.py"
    wrapper.write_text(
        "import sys\n"
        "from pathlib import Path\n"
        "from shop_templates.cli import _bd_dolt_push_smoke_test\n"
        f"rc = _bd_dolt_push_smoke_test(Path({str(target)!r}), {expected_remote!r})\n"
        "sys.exit(rc)\n"
    )
    env = _os.environ.copy()
    env["PATH"] = f"{shim_dir}{_os.pathsep}{env.get('PATH', '')}"
    return subprocess.run(
        [sys.executable, str(wrapper)],
        capture_output=True,
        text=True,
        env=env,
    )


@given(
    parsers.parse(
        'an existing git repository at a target directory "{alias}" with the '
        'beads config rendered by bootstrap and the dolt push remote configured'
    )
)
def given_target_with_beads_config_and_remote_configured(
    alias: str, context: dict, tmp_path: Path
) -> None:
    # Establish the post-config success state by running a success-path
    # bootstrap: `bd dolt remote add` configured the product beads remote, so
    # `bd dolt remote list` lists it. (Behavior A, scenario 0636fba2c1445f9f.)
    context["bootstrap_workspace"] = tmp_path
    context["smoke_test_alias"] = alias
    result = _bootstrap_for_smoke_test(context, tmp_path, fail_dolt_push=False)
    remote_list = _run_bd_shim_query(
        context, context["last_invocation_target"], ["dolt", "remote", "list"]
    )
    expected_remote = _expected_product_beads_remote(
        context["last_invocation_shop_name"]
    )
    assert expected_remote in remote_list.stdout, (
        f"Given premise violated: expected bootstrap to configure the bd dolt "
        f"push remote {expected_remote!r} (bootstrap rc={result.returncode}, "
        f"stderr={result.stderr!r}); `bd dolt remote list` stdout: "
        f"{remote_list.stdout!r}"
    )


@when(
    parsers.parse(
        'the bootstrap smoke-test step runs "bd dolt push" against the '
        'configured dolt remote'
    )
)
def when_smoke_test_runs_against_configured_remote(
    context: dict, tmp_path: Path
) -> None:
    # The success-path bootstrap captured in the Given already ran the
    # smoke-test step end-to-end; the result is on context. The Then steps
    # assert on that captured result.
    assert "cli_returncode" in context, (
        "When step ordering bug: smoke-test ran before a bootstrap invocation "
        "was captured"
    )


@then(
    parsers.parse(
        "the smoke-test reports success and the bootstrap exit code is 0"
    )
)
def then_smoke_test_reports_success_exit_zero(context: dict) -> None:
    # Success-path invocation must have exited 0.
    assert context["cli_returncode"] == 0, (
        f"expected success-path bootstrap to exit 0; got "
        f"{context['cli_returncode']} (stderr: {context['cli_stderr']!r})"
    )
    invocations = _bd_invocations(context)
    expected_remote = _expected_product_beads_remote(
        context["last_invocation_shop_name"]
    )
    # The remote must have been CONFIGURED via `bd dolt remote add` before the
    # push (behavior A); the push itself is a bare `bd dolt push` carrying no
    # positional URL (the real contract).
    remote_adds = [
        inv for inv in invocations if inv[:3] == ["dolt", "remote", "add"]
    ]
    assert remote_adds, (
        f"expected a `bd dolt remote add <name> <url>` subprocess invocation "
        f"to configure the remote before pushing; got bd invocations: "
        f"{invocations!r}"
    )
    assert any(
        expected_remote in inv[3:] for inv in remote_adds
    ), (
        f"expected `bd dolt remote add` to configure the product beads remote "
        f"URL {expected_remote!r}; got remote-add invocations: {remote_adds!r}"
    )
    dolt_pushes = [
        inv for inv in invocations if inv[:2] == ["dolt", "push"]
    ]
    assert dolt_pushes, (
        f"expected a `bd dolt push` subprocess invocation; got bd "
        f"invocations: {invocations!r}"
    )
    for push in dolt_pushes:
        push_args = push[2:]
        idx = 0
        while idx < len(push_args):
            tok = push_args[idx]
            if tok == "--remote":
                idx += 2
                continue
            if tok.startswith("-"):
                idx += 1
                continue
            raise AssertionError(
                f"`bd dolt push` carries an illegal positional argument "
                f"{tok!r}; the real contract takes no positional (use "
                f"`bd dolt remote add`). push invocation: {push!r}"
            )
        assert expected_remote not in push_args, (
            f"`bd dolt push` must not carry the remote URL as a positional "
            f"token; got push invocation: {push!r}"
        )
    combined = context["cli_stdout"] + context["cli_stderr"]
    assert "dolt push" in combined and "success" in combined.lower(), (
        f"expected bootstrap to report `bd dolt push` smoke-test success; "
        f"stdout={context['cli_stdout']!r} stderr={context['cli_stderr']!r}"
    )


@then(
    parsers.parse(
        "given the same target directory with no dolt push remote configured, "
        'when the bootstrap smoke-test step runs "bd dolt push", then it exits '
        "non-zero with a diagnostic naming the missing dolt remote"
    )
)
def then_smoke_test_fails_loud_on_missing_remote(
    context: dict, tmp_path: Path
) -> None:
    # The same target directory, but with NO dolt remote configured. A real
    # `bd dolt push` here is a no-op that exits 0 ("No remote is configured —
    # skipping"); the smoke-test must NOT silently pass on that. It must exit
    # non-zero with a diagnostic that NAMES the missing dolt remote.
    target = context["last_invocation_target"]
    # Strip any configured remote so the smoke-test sees an unconfigured
    # tracker (the missing-remote premise), matching the shim's empty-remote
    # no-op behavior.
    remote_state = target / ".beads" / "__shim_remotes__"
    if remote_state.exists():
        remote_state.unlink()
    result = _run_smoke_test_with_no_remote(context, tmp_path, target)
    assert result.returncode != 0, (
        f"expected the smoke-test to exit non-zero when NO dolt remote is "
        f"configured; got exit 0 (a real `bd dolt push` no-ops and exits 0 on "
        f"an unconfigured tracker, so a bare push silently passes — the guard "
        f"is missing). stdout={result.stdout!r} stderr={result.stderr!r}"
    )
    expected_remote = _expected_product_beads_remote(_SMOKE_TEST_SHOP_NAME)
    diagnostic = result.stdout + result.stderr
    assert "dolt push" in diagnostic, (
        f"expected the no-remote diagnostic to name the `bd dolt push` "
        f"smoke-test; got: {diagnostic!r}"
    )
    # The diagnostic must NAME the missing dolt remote — either the configured
    # remote name (`origin`) or the remote URL — not just a generic failure.
    assert (
        "remote" in diagnostic.lower()
        and (expected_remote in diagnostic or "origin" in diagnostic)
    ), (
        f"expected the diagnostic to NAME the missing dolt remote (the remote "
        f"name 'origin' or URL {expected_remote!r}), not a generic failure; "
        f"got: {diagnostic!r}"
    )


# =======================================================================
# Scenario @1d08c456af08d577 (lead-8vxy / tmpl-urj) — provision is
# lead-driveable: the non-OAuth-secret inputs (owner password, GitHub
# username/PAT) arrive via env/args with NO interactive prompt, and the ONE
# genuine human step (approving the CLAUDE_OAUTH proposal) is isolated into a
# clean lead-presentable handoff: provision creates the proposal, reports the
# proposal number + the EXACT `proposal approve <num> CLAUDE_OAUTH=<value>
# --yes` command for the user to run, and resumes (it does NOT block on an
# interactive ENTER wait). The real Claude OAuth secret is supplied ONLY at
# approve-time; no automated step transports it (lead scenario 11
# @72af524bca85f59c preserved).
#
# Acceptance is grep-predicate over the RENDERED bin/agent-vault-provision body
# (no live broker in the BC env — same render-fidelity style as
# tests/test_ops_provision_oauth_proposal.py /
# tests/test_ops_provision_proposal_scoped_session.py).
# =======================================================================

import re as _re_8vxy


def _provision_body_8vxy(slug: str = "shopsystem") -> str:
    from shop_templates.cli import render_ops_template

    return render_ops_template("agent-vault-provision", slug)


# An interactive prompt is `read` with -p (prompt) or -s (silent) flag and NO
# input redirection on the same line. The `while IFS= read -r line ...` .env
# loop reads from a redirected file, not the terminal, so it is NOT
# interactive; this matcher excludes redirected reads.
_INTERACTIVE_READ_RE_8vxy = _re_8vxy.compile(r"(?<![\w/-])read\b[^\n]*\s-[a-zA-Z]*[ps]")


def _interactive_read_lines_8vxy(body: str) -> list[str]:
    hits = []
    for ln in body.splitlines():
        stripped = ln.strip()
        if stripped.startswith("#"):
            continue
        if "<" in ln and "read" in ln:
            # a read fed from a redirection (e.g. `done < "$ENV_FILE"`) is not
            # interactive; skip lines carrying an input redirect.
            continue
        if _INTERACTIVE_READ_RE_8vxy.search(ln):
            hits.append(ln)
    return hits


@given("a running agent-vault broker with an empty vault")
def given_running_broker_empty_vault_8vxy(context: dict) -> None:
    # Render-fidelity premise: the BC env has no live broker, so the scenario's
    # acceptance is asserted against the RENDERED provision body (the shape the
    # lead runs against a real empty-vault broker). Capture the rendered body.
    context["provision_body_8vxy"] = _provision_body_8vxy()


@given(
    "the owner password and the GitHub username and PAT are supplied via "
    "environment variables or arguments"
)
def given_inputs_via_env_or_args_8vxy(context: dict) -> None:
    body = context.setdefault("provision_body_8vxy", _provision_body_8vxy())
    # The non-OAuth inputs each have an env-supplied source in the rendered
    # body (owner password / github username / github token).
    assert 'OWNER_PASSWORD="${AGENT_VAULT_OWNER_PASSWORD' in body, (
        "owner password must be sourced from the AGENT_VAULT_OWNER_PASSWORD env var"
    )
    assert 'GITHUB_USERNAME="${GITHUB_USERNAME' in body, (
        "GitHub username must be sourced from the GITHUB_USERNAME env var"
    )
    assert 'GITHUB_TOKEN="${GITHUB_TOKEN' in body, (
        "GitHub PAT must be sourced from the GITHUB_TOKEN env var"
    )


@when("the lead runs bin/agent-vault-provision")
def when_lead_runs_provision_8vxy(context: dict) -> None:
    context.setdefault("provision_body_8vxy", _provision_body_8vxy())


@then(
    "it consumes the owner password and the GitHub username and PAT from the "
    "environment or arguments without any interactive prompt"
)
def then_consumes_inputs_no_prompt_8vxy(context: dict) -> None:
    body = context["provision_body_8vxy"]
    # No interactive `read -s`/`read -p` prompt anywhere in the script: the
    # non-OAuth inputs come from env/args, AND the OAuth approval handoff must
    # NOT block on an interactive ENTER wait (provision reports + resumes).
    interactive = _interactive_read_lines_8vxy(body)
    assert not interactive, (
        "provision must consume its inputs without any interactive prompt and "
        "must not block on an interactive read; found interactive read "
        f"line(s): {interactive!r}"
    )


@then(
    "it stores the GitHub credential in the vault without the lead handling "
    "any real Claude OAuth secret"
)
def then_stores_github_no_real_oauth_8vxy(context: dict) -> None:
    body = context["provision_body_8vxy"]
    # The GitHub credential is stored from env-sourced vars via `credential set`.
    assert "agent-vault vault credential set" in body, (
        "provision must store the GitHub credential via `vault credential set`"
    )
    assert "GITHUB_USERNAME=${GITHUB_USERNAME}" in body, (
        "the stored GitHub username credential must come from $GITHUB_USERNAME"
    )
    assert "GITHUB_TOKEN=${GITHUB_TOKEN}" in body, (
        "the stored GitHub PAT credential must come from $GITHUB_TOKEN"
    )
    # No automated step stores/transports a real CLAUDE_OAUTH secret value: the
    # OAuth credential never flows through a flat `credential set`.
    for ln in body.splitlines():
        if "credential set" in ln and not ln.strip().startswith("#"):
            assert "CLAUDE_OAUTH" not in ln, (
                f"no automated `credential set` may carry a real CLAUDE_OAUTH "
                f"secret (it arrives only at approve-time): {ln!r}"
            )


@then(
    'it creates a CLAUDE_OAUTH proposal and reports the proposal number '
    'together with the exact "proposal approve <num> CLAUDE_OAUTH=<value> '
    '--yes" command for the user to run'
)
def then_creates_proposal_reports_handoff_8vxy(context: dict) -> None:
    body = context["provision_body_8vxy"]
    # (a) creates a CLAUDE_OAUTH proposal.
    assert "agent-vault vault proposal create" in body, (
        "provision must create the CLAUDE_OAUTH proposal"
    )
    # (b) captures + reports the proposal NUMBER.
    assert "PROPOSAL_NUM=" in body, (
        "provision must capture the proposal number for the handoff"
    )
    # (c) reports the EXACT approve command shape the user runs. The handoff
    # must surface the literal `proposal approve <num> CLAUDE_OAUTH=<value>
    # --yes` command — substituting the captured proposal number for <num>,
    # while keeping the `CLAUDE_OAUTH=<value>` placeholder (the user supplies
    # the real value) and the `--yes` flag. Match the rendered approve line
    # carrying the captured number var, the CLAUDE_OAUTH= assignment, and --yes.
    approve_lines = [
        ln for ln in body.splitlines()
        if "proposal approve" in ln and "${PROPOSAL_NUM" in ln
    ]
    assert approve_lines, (
        "the handoff must report the exact approve command with the captured "
        "proposal number substituted for <num> (a `proposal approve "
        "${PROPOSAL_NUM...} CLAUDE_OAUTH=<value> --yes` line)"
    )
    has_exact = any(
        ("CLAUDE_OAUTH=" in ln) and ("--yes" in ln) for ln in approve_lines
    )
    assert has_exact, (
        "the reported approve command must be the exact "
        "`proposal approve <num> CLAUDE_OAUTH=<value> --yes` shape "
        "(carrying the CLAUDE_OAUTH=<value> placeholder and the --yes flag); "
        f"got approve line(s): {approve_lines!r}"
    )


@then(
    "the real Claude OAuth secret is supplied only at approve-time and no "
    "automated step transports it"
)
def then_secret_only_at_approve_time_8vxy(context: dict) -> None:
    body = context["provision_body_8vxy"]
    # The proposal slot carries NO value field (server rejects a value for
    # oauth creds; tokens arrive via approve), and the approve command leaves
    # the real value as a <value> placeholder for the user — no automated step
    # carries a real CLAUDE_OAUTH secret.
    assert '"value"' not in body, (
        "the oauth proposal slot must not carry a value field — the real "
        "secret is supplied only at approve-time"
    )
    # The approve command must NOT inline a real secret; it leaves a <value>
    # placeholder the user fills.
    approve_lines = [ln for ln in body.splitlines() if "proposal approve" in ln]
    assert approve_lines, "approve command must render"
    assert any("CLAUDE_OAUTH=<" in ln for ln in approve_lines), (
        "the approve command must keep CLAUDE_OAUTH=<...> a placeholder for the "
        "user to fill at approve-time; no automated step may transport a real "
        f"value: {approve_lines!r}"
    )


