def _bootstrap_pre_render_code(body: str) -> str:
    render = body.find("shop-templates bootstrap")
    pre = body[:render] if render != -1 else body
    return "\n".join(
        s for s in (ln.strip() for ln in pre.splitlines())
        if s and not s.startswith("#")
    )


